import React, { useState } from "react";
import "./Dashboard.css";

export default function Dashboard({ employee }) {
  // Dashboard home page with employee data
  return (
    <div className="dash-wrapper" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
      {/* Employee Info */}
      <div style={{ background: '#fff', borderRadius: 16, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', padding: '24px 32px', marginBottom: 32, minWidth: 320, textAlign: 'center' }}>
        <div style={{ fontSize: 22, fontWeight: 700, color: '#0f9d58', marginBottom: 8 }}>
          {employee?.empName || 'Employee Name'}
        </div>
        <div style={{ fontSize: 16, color: '#222', marginBottom: 4 }}>
          <b>ID:</b> {employee?.empId || 'N/A'}
        </div>
        <div style={{ fontSize: 16, color: '#222', marginBottom: 4 }}>
          <b>Department:</b> {employee?.department || 'N/A'}
        </div>
        <div style={{ fontSize: 16, color: '#222' }}>
          <b>Role:</b> {employee?.role || employee?.title || 'N/A'}
        </div>
      </div>
      {/* Dashboard Menus */}
      <div style={{ display: 'flex', gap: 32 }}>
        <div style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Dashboard
        </div>
        <div style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Add New
        </div>
        <div style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', transition: 'border 0.2s, box-shadow 0.2s' }}>
          History
        </div>
        <div style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Tools
        </div>
      </div>
    </div>
  );
}
